type Customer = {
  yearsAsCustomer: number;
  quoteCount: number;
};

type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const PROCESSING_FEE = 5;

export function quote(customer: Customer, items: Item[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  const basePremium = BASE_PREMIUMS[items[0].type];
  return basePremium * 1.1 + PROCESSING_FEE;
}

